import type { InterviewSimulationSet, ScenarioQuestion } from "./scenario-questions/types";

type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D, star?: { situation: string; task: string; action: string; result: string }): ScenarioQuestion {
  return { id, formatType: star ? "star" : "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d, ...(star ? { starBreakdown: star } : {}) };
}

export const interviewSimulationSets: InterviewSimulationSet[] = [
  {
    id: "sim-behavioral-foundations",
    title: "Behavioral Interview Foundations",
    description: "Practice answering common behavioral nursing interview questions using the STAR method. Build confidence in presenting your clinical experiences effectively.",
    category: "interview_preparation",
    difficulty: "beginner",
    estimatedMinutes: 45,
    questions: [
      q("sim1-1","interview_preparation","behavioral","You need to introduce yourself professionally.","Tell me about yourself and why you chose nursing.","I am a recent BSN graduate with clinical experience in medical-surgical, pediatric, and community health settings. I chose nursing because I wanted a career that combines scientific knowledge with meaningful human connection. My experience as a CNA reinforced my decision when I saw firsthand how quality nursing care transforms patient outcomes.","Professional introduction with clear motivation.","beginner",{situation:"I was working as a CNA when I decided to pursue nursing.",task:"I needed to determine my career path and commit to nursing education.",action:"I enrolled in a BSN program while continuing to work as a CNA, gaining both academic knowledge and practical experience.",result:"I graduated with honors and clinical skills that prepared me for professional nursing practice."}),
      q("sim1-2","interview_preparation","behavioral","You are asked about teamwork.","Describe a time you worked effectively as part of a team.","During my capstone rotation, our unit experienced a staffing crisis. I coordinated with the charge nurse to redistribute patient assignments, helped cover medication passes for an overwhelmed colleague, and ensured all patients received timely care. The shift ran smoothly despite the staffing challenge.","Specific teamwork under challenging conditions.","beginner",{situation:"Our unit was short-staffed during a busy shift.",task:"We needed to ensure safe patient care despite having fewer nurses.",action:"I volunteered to take extra patients, helped organize task distribution, and communicated proactively with the team.",result:"All patients received safe, timely care and no adverse events occurred despite the staffing gap."}),
      q("sim1-3","interview_preparation","behavioral","You faced a conflict with a colleague.","Tell me about a time you managed a workplace conflict.","A clinical partner and I disagreed about patient positioning for a post-operative patient. Rather than arguing, I consulted the evidence-based protocol, discussed it respectfully, and we agreed to follow the guideline. We resolved the conflict professionally and the patient received appropriate care.","Evidence-based conflict resolution.","beginner",{situation:"My clinical partner and I disagreed about proper positioning for a post-operative patient.",task:"I needed to resolve the disagreement without escalating the conflict while ensuring correct patient care.",action:"I calmly suggested we review the post-operative protocol together. We found the evidence-based recommendation and both agreed to follow it.",result:"The patient was positioned correctly, and my partner and I developed a stronger working relationship based on mutual respect."}),
      q("sim1-4","interview_preparation","behavioral","You adapted to an unexpected change.","Describe a time you had to adapt quickly.","My psychiatric rotation was cancelled due to facility issues, and I was reassigned to an ICU observation. I researched ICU-relevant content overnight, arrived prepared, and the exposure to critical care nursing actually helped me develop hemodynamic monitoring skills I would not have gained otherwise.","Rapid adaptation yielding unexpected benefits.","beginner",{situation:"My planned clinical rotation was cancelled 24 hours before it started.",task:"I needed to prepare for an entirely different clinical environment overnight.",action:"I reviewed critical care nursing content, familiarized myself with common ICU equipment, and approached the new rotation with curiosity rather than frustration.",result:"I gained valuable ICU exposure and discovered an interest in critical care that I would not have explored otherwise."}),
      q("sim1-5","interview_preparation","behavioral","You demonstrated patient advocacy.","Give an example of when you advocated for a patient.","A patient was in visible pain but hesitant to ask for medication because they feared being labeled a drug seeker. I assessed their pain objectively, documented my findings, and communicated their pain level to the physician using SBAR. The physician adjusted the pain management plan, and the patient's comfort improved significantly.","Pain advocacy removing patient stigma concerns.","beginner",{situation:"A patient was clearly in pain but reluctant to request medication.",task:"I needed to advocate for adequate pain management while respecting the patient's concerns.",action:"I assessed pain using objective tools, validated the patient's feelings, and communicated the clinical findings to the physician.",result:"The pain management plan was adjusted, and the patient experienced significant relief while feeling respected."}),
      q("sim1-6","interview_preparation","behavioral","You handled a stressful situation.","How do you manage stress in clinical settings?","During a simulation where a patient was coding, I felt my heart racing but focused on my training. I followed the ACLS algorithm, communicated clearly with my team, and performed my assigned role effectively. Afterward, I debriefed with my instructor about what I did well and what I could improve.","Controlled stress response with reflective practice.","beginner",{situation:"I was in a high-fidelity simulation where the patient was in cardiac arrest.",task:"I needed to manage my stress response while performing life-saving interventions.",action:"I used focused breathing, followed the ACLS algorithm step by step, and communicated clearly with team members.",result:"The simulation was managed successfully, and my instructor noted my composure under pressure."}),
      q("sim1-7","interview_preparation","behavioral","You made a mistake and learned from it.","Tell me about a time you made a mistake. What did you learn?","I documented assessment findings in the wrong patient's chart during a busy clinical day. I discovered the error during my end-of-shift review. I immediately corrected both charts, reported to my instructor, and developed a verification habit of always checking the patient name banner before documenting.","Honest error disclosure with system improvement.","beginner",{situation:"During a busy clinical day, I accidentally documented in the wrong patient's chart.",task:"I needed to correct the error, report it honestly, and prevent future occurrences.",action:"I corrected both charts, reported to my clinical instructor immediately, and developed a new habit of always verifying the patient name banner before charting.",result:"The error was corrected without patient harm, and I never made the same mistake again."}),
      q("sim1-8","interview_preparation","behavioral","You demonstrated initiative.","Give an example of when you showed initiative in a clinical setting.","I noticed that patient education materials on our unit were outdated and did not reflect current guidelines. Without being asked, I researched updated evidence, drafted new education sheets, and presented them to the charge nurse. The unit adopted the updated materials and patient understanding scores improved.","Self-initiated quality improvement.","beginner",{situation:"Patient education materials on the unit were outdated and inconsistent with current evidence.",task:"I wanted to improve education quality without waiting to be asked.",action:"I researched current guidelines, created updated education materials, and presented them to the unit leadership for approval.",result:"The new materials were adopted, and patient education assessment scores improved measurably."}),
      q("sim1-9","interview_preparation","behavioral","You received constructive criticism.","How do you respond to constructive criticism?","My preceptor told me my medication passes were thorough but too slow, which was delaying other patient care. Instead of being defensive, I asked for specific tips on improving efficiency. I implemented her suggestions—batching preparations and using a medication administration checklist—and reduced my medication pass time by 20 minutes.","Non-defensive improvement from criticism.","beginner",{situation:"My preceptor observed that my medication administration was too slow.",task:"I needed to improve my medication pass efficiency without sacrificing safety.",action:"I asked for specific improvement strategies and implemented systematic changes: batching preparations, using checklists, and organizing by patient proximity.",result:"My medication pass time improved by 20 minutes while maintaining accuracy and safety."}),
      q("sim1-10","interview_preparation","behavioral","You are asked about your greatest strength.","What is your greatest strength as a nurse?","My greatest strength is my ability to remain calm and think systematically during emergencies. During clinical, my peers and instructors consistently noted that I maintain composure during codes and rapid responses. I attribute this to thorough preparation and a commitment to following evidence-based protocols regardless of the emotional intensity of the situation.","Specific strength with clinical evidence.","beginner",{situation:"I have consistently demonstrated composure during high-stress clinical situations.",task:"I needed to manage emergency situations effectively while supporting my team.",action:"I relied on algorithmic thinking, clear communication, and emotional regulation techniques during every emergency.",result:"My instructors consistently evaluated my emergency response skills as above expectations."}),
      q("sim1-11","interview_preparation","behavioral","You managed competing priorities.","Describe a time you had to prioritize competing demands.","During a clinical shift, I had a patient returning from surgery, a discharge to complete, and a medication pass due. I prioritized the post-surgical assessment as the highest acuity, delegated discharge paperwork preparation to support staff, and administered time-critical medications between tasks. All three were completed safely and on time.","Priority-based task management with delegation.","beginner",{situation:"Three time-sensitive tasks arose simultaneously during a clinical shift.",task:"I needed to manage all three without compromising patient safety.",action:"I triaged by acuity, delegated preparation tasks, and clustered my workflow to move efficiently between patients.",result:"All tasks were completed safely within the required timeframes."}),
      q("sim1-12","interview_preparation","behavioral","You demonstrated compassion.","Give an example of compassionate care you provided.","An elderly patient was crying alone at 2 AM during my night shift. Instead of just asking if they needed medication, I sat with them and listened. They were grieving a spouse who had recently died and were afraid of being alone. I arranged for the chaplain the next morning and ensured the care team addressed their emotional needs in the care plan.","Holistic compassion beyond physical care.","beginner",{situation:"I found an elderly patient crying alone during a night shift.",task:"I needed to address their emotional needs alongside their physical care.",action:"I sat with the patient, listened to their story, validated their grief, and coordinated support services including chaplain and social work.",result:"The patient felt heard and supported. The care team incorporated emotional support into the care plan."}),
      q("sim1-13","interview_preparation","behavioral","You collaborated with another discipline.","Describe effective interdisciplinary collaboration.","I worked with the physical therapist to create a coordinated ambulation schedule for a post-stroke patient. By aligning PT sessions with medication timing for pain management, the patient was able to participate more fully in therapy and achieved mobility goals two days ahead of schedule.","Cross-discipline coordination improving outcomes.","intermediate",{situation:"A post-stroke patient was struggling with physical therapy due to pain during sessions.",task:"I needed to coordinate with PT to optimize the patient's therapy participation.",action:"I aligned pain medication timing with PT sessions, communicated the patient's optimal function periods, and participated in joint goal-setting.",result:"The patient participated more fully in therapy and achieved mobility goals two days ahead of the projected timeline."}),
      q("sim1-14","interview_preparation","behavioral","You handled an ethical dilemma.","Tell me about an ethical situation you encountered.","A patient's family wanted to withhold a terminal diagnosis from the patient. I advocated for the patient's right to know their own medical information while being sensitive to the family's protective instincts. I facilitated a meeting between the physician, family, and patient where the information was shared compassionately with family support present.","Ethical advocacy with family sensitivity.","intermediate",{situation:"A family requested that their loved one not be told about their terminal diagnosis.",task:"I needed to balance patient autonomy with family concerns while maintaining trust.",action:"I discussed the ethical principle of patient autonomy with the family, facilitated a compassionate physician-family-patient meeting, and provided emotional support throughout.",result:"The patient was informed with family support present, and both the patient and family expressed gratitude for the sensitive approach."}),
      q("sim1-15","interview_preparation","behavioral","You improved a process or system.","Describe a time you improved a clinical process.","I noticed that medication reconciliation during admissions was frequently incomplete, leading to potential drug interactions. I proposed a standardized checklist that prompted nurses to verify home medications, OTC drugs, supplements, and allergies. After implementation, medication reconciliation completeness improved from 72% to 96%.","Data-driven process improvement with measurable results.","intermediate",{situation:"Medication reconciliation completeness was below target on our unit.",task:"I needed to identify and address the root cause of incomplete reconciliation.",action:"I audited current practices, identified common omission patterns, and created a standardized checklist addressing each gap.",result:"Reconciliation completeness improved from 72% to 96%, reducing potential drug interaction risks."}),
      q("sim1-16","interview_preparation","behavioral","You managed a difficult patient interaction.","Tell me about a time you cared for a challenging patient.","A patient was verbally aggressive toward all staff. Instead of avoiding the room, I approached with curiosity about their frustration. I discovered they had been waiting 4 hours for test results with no communication. I obtained the results, facilitated a physician visit, and the patient's behavior completely changed once their information needs were met.","Root cause exploration of difficult behavior.","intermediate",{situation:"A patient was verbally aggressive toward all nursing staff.",task:"I needed to provide safe care while understanding and addressing the root cause of their behavior.",action:"I approached the patient with empathy, identified the underlying frustration (information deprivation), and addressed the unmet need.",result:"The patient became cooperative and later apologized for their behavior. Their satisfaction improved significantly."}),
      q("sim1-17","interview_preparation","behavioral","You demonstrated leadership during uncertainty.","Describe a time you led during an uncertain situation.","When our unit received a patient with an unfamiliar infectious disease requiring novel precautions, I took the initiative to research the latest CDC guidelines, created a quick-reference precaution card, and briefed the nursing team before the patient arrived. This proactive approach prevented confusion and ensured consistent infection control.","Proactive leadership during clinical uncertainty.","intermediate",{situation:"Our unit was receiving a patient with a rare infectious disease requiring unfamiliar precautions.",task:"I needed to ensure the team was prepared with current evidence-based protocols before the patient arrived.",action:"I researched CDC guidelines, created visual reference cards, and led a brief team huddle to review the precautions.",result:"The patient was safely admitted with consistent precaution adherence and no exposure events."}),
      q("sim1-18","interview_preparation","behavioral","You balanced patient preferences with clinical needs.","Give an example of respecting patient autonomy while ensuring safety.","A diabetic patient refused to follow their prescribed diet, saying they wanted to enjoy food during their hospitalization. I negotiated a compromise: I involved the dietitian to create a modified menu that incorporated some of their preferred foods while maintaining blood sugar management. The patient was more compliant with the adjusted plan.","Creative compromise between autonomy and safety.","intermediate",{situation:"A diabetic patient was refusing their prescribed diet.",task:"I needed to respect patient autonomy while ensuring clinical safety.",action:"I explored the patient's food preferences, collaborated with the dietitian to modify the meal plan, and educated the patient about which modifications were possible.",result:"The patient was more satisfied and compliant, and blood sugar management improved with the modified approach."}),
      q("sim1-19","interview_preparation","behavioral","You managed a time when you did not have enough information.","How do you make decisions with incomplete information?","A patient's medication history was unavailable during an emergency admission. I prioritized patient safety by holding non-emergent medications, administering only critical treatments, and using multiple sources (patient interview, pharmacy records, family contacts) to reconstruct the medication list as quickly as possible.","Safe decision-making with incomplete data.","intermediate",{situation:"A patient was admitted emergently without medication history available.",task:"I needed to provide safe care despite incomplete medication information.",action:"I held non-emergent medications, administered only critical treatments, and systematically gathered medication history from multiple sources.",result:"The medication list was reconstructed within 4 hours without any adverse events from the temporary holds."}),
      q("sim1-20","interview_preparation","behavioral","You are asked where you see yourself in 5 years.","Where do you see your nursing career in 5 years?","In 5 years, I see myself as a confident, certified nurse in my specialty area, actively mentoring new graduates and contributing to evidence-based practice on my unit. I plan to pursue specialty certification within 2 years and begin my graduate education by year 4. I want to be the resource nurse that new staff seek out for guidance.","Specific, achievable career vision with milestones.","beginner",{situation:"I am beginning my nursing career with specific professional development goals.",task:"I needed to develop a realistic but ambitious 5-year career plan.",action:"I identified progressive milestones: clinical mastery, certification, mentoring, and graduate education.",result:"My career plan demonstrates commitment to growth while maintaining realistic, achievable benchmarks."}),
    ]
  },
  {
    id: "sim-clinical-scenarios",
    title: "Clinical Scenario Interview Practice",
    description: "Practice responding to clinical judgment questions commonly asked in nursing interviews. Demonstrate your critical thinking and patient safety focus.",
    category: "interview_preparation",
    difficulty: "intermediate",
    estimatedMinutes: 50,
    questions: [
      q("sim2-1","interview_preparation","clinical_judgment","A patient's blood pressure is 200/110.","How would you manage a hypertensive emergency?","I would assess for end-organ damage symptoms (headache, vision changes, chest pain), keep the patient calm and in a comfortable position, administer prescribed antihypertensives, notify the provider immediately, and monitor vital signs every 5-10 minutes. Controlled reduction is critical—dropping BP too fast can cause stroke.","Controlled hypertensive emergency management.","intermediate"),
      q("sim2-2","interview_preparation","clinical_judgment","A patient develops anaphylaxis after a medication.","What is your immediate response to anaphylaxis?","I would call a code, administer epinephrine IM (0.3-0.5 mg of 1:1000), establish IV access, provide supplemental oxygen, prepare for possible intubation, administer diphenhydramine and corticosteroids, and position supine with legs elevated unless contraindicated. Time is critical—epinephrine should be given within minutes.","Anaphylaxis emergency protocol execution.","intermediate"),
      q("sim2-3","interview_preparation","clinical_judgment","You notice a change in a patient's neurological status.","How would you assess a neurological change?","I would perform a focused neuro assessment: Glasgow Coma Scale, pupil size and reactivity, motor strength, speech quality, and vital signs. I would compare to baseline, check blood glucose, review medications, and notify the provider using SBAR with my specific findings. Neurological changes require urgent evaluation.","Systematic neurological change assessment.","intermediate"),
      q("sim2-4","interview_preparation","clinical_judgment","A patient on oxygen therapy removes their nasal cannula.","How would you manage a patient refusing oxygen?","I would explain why oxygen is important for their condition, address their discomfort with the nasal cannula, offer alternatives (humidification, different delivery method), and document their refusal if they persist. I would monitor SpO2 closely and notify the provider. Patient education about oxygen's role often improves compliance.","Oxygen refusal management with alternatives.","beginner"),
      q("sim2-5","interview_preparation","clinical_judgment","A diabetic patient is found unresponsive.","What is your priority assessment for an unresponsive diabetic patient?","I would check blood glucose immediately—hypoglycemia is the most likely reversible cause. I would assess airway, breathing, and circulation. If hypoglycemic, I would administer IV dextrose or glucagon. If hyperglycemic, I would anticipate DKA management. For any unresponsive patient, I would call for help and follow emergency protocols.","Rapid glucose assessment in unresponsive diabetic patients.","intermediate"),
      q("sim2-6","interview_preparation","clinical_judgment","A post-operative patient has no urine output for 4 hours.","How would you assess post-operative oliguria?","I would palpate for bladder distension, check the catheter for kinks or obstruction, irrigate if ordered, review fluid balance and blood loss during surgery, assess vital signs, and notify the surgeon. Post-operative oliguria can indicate hypovolemia, urinary retention, or early renal compromise requiring prompt evaluation.","Post-operative oliguria systematic assessment.","intermediate"),
      q("sim2-7","interview_preparation","clinical_judgment","A patient complains of sudden, severe headache.","What does a thunderclap headache require?","A sudden severe headache—the worst headache of the patient's life—requires immediate evaluation for subarachnoid hemorrhage until proven otherwise. I would perform a neurological assessment, keep the patient calm and in a dark quiet environment, obtain vital signs, and notify the provider for emergent CT scan without contrast. This is a neurosurgical emergency.","Thunderclap headache as a neurosurgical emergency.","advanced"),
      q("sim2-8","interview_preparation","clinical_judgment","A patient receiving a blood transfusion develops flank pain and dark urine.","What type of transfusion reaction is this?","Flank pain and dark urine during blood transfusion indicate an acute hemolytic transfusion reaction—the most dangerous type. I would stop the transfusion immediately, disconnect the blood tubing, maintain IV access with new tubing and normal saline, notify the provider and blood bank, send blood and urine samples, and monitor for shock and DIC.","Acute hemolytic transfusion reaction recognition.","advanced"),
      q("sim2-9","interview_preparation","clinical_judgment","A patient with COPD is on a non-rebreather mask at 15L.","When would you use a non-rebreather in COPD?","A non-rebreather at 15L delivers near 100% oxygen. While COPD patients typically receive low-flow oxygen, in life-threatening emergencies (acute respiratory failure, severe hypoxemia), high-flow oxygen is appropriate because preventing death takes priority over theoretical CO2 retention concerns. The key is close monitoring and readiness to support ventilation.","Emergency oxygen override in COPD.","advanced"),
      q("sim2-10","interview_preparation","clinical_judgment","A patient develops symptoms of sepsis.","How would you implement the sepsis bundle?","I would recognize the sepsis indicators (fever, tachycardia, hypotension, altered mental status, elevated WBC/lactate), implement the 1-hour bundle: obtain blood cultures, administer broad-spectrum antibiotics, begin fluid resuscitation with 30 mL/kg crystalloid, measure lactate, and apply vasopressors if MAP remains below 65 despite fluids. Time-to-antibiotics is the most critical factor.","Sepsis bundle implementation with time urgency.","intermediate"),
      q("sim2-11","interview_preparation","clinical_judgment","A patient on a PCA pump is difficult to arouse with a respiratory rate of 6.","How would you manage opioid-induced respiratory depression?","I would stop the PCA immediately, stimulate the patient vigorously, call for help, administer naloxone (Narcan) as ordered, bag-valve-mask ventilate if needed, and monitor closely as naloxone has a shorter duration than most opioids. I would reassess the pain management plan with the provider.","Opioid reversal emergency management.","intermediate"),
      q("sim2-12","interview_preparation","clinical_judgment","A patient has a blood glucose of 600 with fruity breath and Kussmaul respirations.","What emergency is this and how would you respond?","This presentation indicates diabetic ketoacidosis—a life-threatening hyperglycemic emergency. I would begin aggressive IV normal saline resuscitation, start an insulin drip per protocol, monitor potassium closely (insulin drives potassium into cells), check ABG for acidosis severity, and monitor blood glucose hourly. Potassium replacement is often needed as insulin corrects the hyperglycemia.","DKA emergency with potassium awareness.","advanced"),
      q("sim2-13","interview_preparation","clinical_judgment","A patient with chest pain has ST elevation on the 12-lead ECG.","What does STEMI require?","ST elevation MI requires emergent reperfusion therapy—the goal is 'door-to-balloon' time under 90 minutes for PCI. I would administer aspirin, obtain IV access, administer heparin and nitroglycerin as ordered, prepare for cardiac catheterization lab activation, and provide emotional support. Every minute of delay increases myocardial damage.","STEMI time-critical intervention.","advanced"),
      q("sim2-14","interview_preparation","clinical_judgment","A patient develops acute pulmonary embolism with hemodynamic instability.","How would you manage a massive PE?","A massive PE with hemodynamic instability (hypotension, shock) requires aggressive treatment: supplemental oxygen or intubation, IV fluid bolus, vasopressor support, systemic anticoagulation with heparin, and possible thrombolytic therapy. I would prepare for possible surgical embolectomy. I would not delay treatment for diagnostic confirmation if clinical suspicion is high and the patient is decompensating.","Massive PE emergency management.","advanced"),
      q("sim2-15","interview_preparation","clinical_judgment","A patient with a chest tube has sudden loss of water seal fluctuation.","What does loss of tidaling in a chest tube indicate?","Loss of tidaling can indicate: the lung has re-expanded (good outcome), the tube is kinked or clogged (concerning), or the tube has become displaced. I would assess the patient's respiratory status, check the tubing for kinks, verify all connections are tight, assess the insertion site, and notify the provider. A chest X-ray will confirm lung re-expansion.","Chest tube troubleshooting for loss of function.","intermediate"),
      q("sim2-16","interview_preparation","clinical_judgment","A patient on a mechanical ventilator has high peak airway pressures.","What causes elevated peak pressures on a ventilator?","Elevated peak pressures indicate increased resistance or decreased compliance: mucus plugging, bronchospasm, pneumothorax, patient-ventilator asynchrony, or tube migration. I would suction the airway, assess breath sounds, check tube position, administer bronchodilators if wheezing is present, and notify the RT and provider. If pressure is dangerously high, I would hand-ventilate while troubleshooting.","Ventilator high-pressure alarm troubleshooting.","advanced"),
      q("sim2-17","interview_preparation","clinical_judgment","A patient on contact isolation requires emergent intubation.","How do you balance emergency response with infection control?","I would don appropriate PPE as quickly as possible without delaying life-saving intervention. In a true emergency, saving the patient's life takes priority—I would protect myself with available PPE (at minimum gloves and mask) while initiating emergency care. Full PPE compliance is essential but cannot cause fatal delays.","Emergency-infection control balance.","intermediate"),
      q("sim2-18","interview_preparation","clinical_judgment","A trauma patient presents with a tension pneumothorax.","How would you recognize and respond to tension pneumothorax?","Tension pneumothorax presents with severe respiratory distress, absent breath sounds on one side, tracheal deviation away from the affected side, distended neck veins, and hypotension. I would notify the provider for emergent needle decompression at the second intercostal space, midclavicular line. This is immediately life-threatening and requires intervention before imaging.","Tension pneumothorax clinical recognition and response.","advanced"),
      q("sim2-19","interview_preparation","clinical_judgment","A patient on anticoagulation develops a GI bleed.","How would you manage an active GI bleed in an anticoagulated patient?","I would assess hemodynamic stability, establish two large-bore IVs, send type and crossmatch and CBC, hold anticoagulation, notify the provider and GI team, prepare for possible blood transfusion, monitor vital signs every 15 minutes, and anticipate endoscopy. The challenge is balancing bleeding control with the underlying condition requiring anticoagulation.","GI bleed in anticoagulated patients.","advanced"),
      q("sim2-20","interview_preparation","clinical_judgment","A patient is experiencing status epilepticus.","How would you manage status epilepticus?","Status epilepticus is a neurological emergency—continuous seizure activity lasting >5 minutes. I would ensure airway protection, administer benzodiazepines (lorazepam IV first-line), prepare for second-line agents (phenytoin or levalbuterol), time the seizure, call for help, protect the patient from injury, and prepare for possible intubation. The longer status persists, the harder it is to terminate.","Status epilepticus emergency management.","advanced"),
    ]
  },
  {
    id: "sim-workplace-readiness",
    title: "Workplace Readiness Scenarios",
    description: "Practice responding to common workplace scenarios you will encounter as a new graduate nurse. Focus on prioritization, delegation, and team communication.",
    category: "workplace_scenarios",
    difficulty: "beginner",
    estimatedMinutes: 40,
    questions: [
      q("sim3-1","workplace_scenarios","prioritization","You have four patients with varying needs.","How would you prioritize your morning assessment?","I would see the most acute patient first—the post-operative patient with drain monitoring needs. Then the patient with overnight vital sign changes. Then the stable chronic patient. Finally the patient awaiting discharge. I would assess the highest risk for deterioration first.","Acuity-based assessment prioritization.","beginner"),
      q("sim3-2","workplace_scenarios","prioritization","A patient is requesting pain medication while another patient's IV pump is alarming.","Which do you address first?","I would quickly assess the IV pump alarm—if it is a simple end-of-bag alarm, I would silence it and go get the pain medication first. If the alarm indicates a safety concern (air in line, infiltration), I would address it immediately. The type of alarm determines priority.","Alarm assessment before automatic response.","beginner"),
      q("sim3-3","workplace_scenarios","delegation","You need to delegate morning vital signs.","How would you delegate morning vital signs to a CNA?","I would specify which patients need vitals, any special parameters (orthostatic BPs for room 302), and critical values to report immediately: 'Any systolic below 90 or above 180, heart rate below 50 or above 120, temp above 101.5, or SpO2 below 92%—come find me immediately.'","Clear vital sign delegation with critical parameters.","beginner"),
      q("sim3-4","workplace_scenarios","delegation","You need help repositioning a heavy patient.","How would you coordinate safe patient repositioning?","I would ensure adequate staff (at least 2 for most patients, 3 for bariatric), use proper lifting equipment (slide sheet, Hoyer lift), communicate the plan before starting, count together to coordinate the move, and check patient comfort and skin integrity after repositioning.","Safe patient handling coordination.","beginner"),
      q("sim3-5","workplace_scenarios","patient_safety","You notice a wet floor in a patient hallway.","How would you address an environmental safety hazard?","I would immediately place a wet floor sign, notify environmental services for cleanup, warn any patients or visitors in the area, and monitor the area until it is dry. Environmental safety is everyone's responsibility—I would not walk past a hazard without addressing it.","Immediate environmental hazard management.","beginner"),
      q("sim3-6","workplace_scenarios","patient_safety","A patient's blood sugar is 50.","How would you manage moderate hypoglycemia?","I would assess the patient's consciousness and ability to swallow. If alert, I would give 15 grams of fast-acting glucose (4 oz juice or glucose tablets), recheck in 15 minutes, and repeat if still below 70. I would hold any scheduled insulin, notify the provider, and investigate the cause.","Rule of 15 for hypoglycemia management.","beginner"),
      q("sim3-7","workplace_scenarios","medication_error","You realize you gave a medication 30 minutes early.","How would you handle an early medication administration?","I would assess whether the 30-minute variance is within the facility's acceptable administration window (many allow 30 minutes before or after). If outside the window, I would assess for adverse effects, adjust the next dose timing, document the actual time given, and notify the provider if clinically significant.","Medication timing variance assessment.","beginner"),
      q("sim3-8","workplace_scenarios","handoff_communication","You are preparing to give your first shift report.","How would you organize your handoff report?","I would use SBAR: Situation (patient name, diagnosis, current status), Background (relevant history, overnight events), Assessment (current findings, vital signs, recent labs), Recommendation (pending tasks, things to watch for, expected events). I would be concise and focus on what the next nurse needs to know for safe care.","Organized first handoff using SBAR.","beginner"),
      q("sim3-9","workplace_scenarios","difficult_coworkers","A more experienced nurse says your assessment technique is wrong.","How would you respond to criticism of your technique?","I would listen without defensiveness and ask them to show me their technique. If it differs from what I learned, I would compare both approaches to the facility protocol. I would thank them for the feedback regardless. I would adopt the better technique and seek clarification from my preceptor if still uncertain.","Open-minded technique correction.","beginner"),
      q("sim3-10","workplace_scenarios","interdisciplinary_communication","A physician gives you a verbal order you do not understand.","How would you handle an unclear verbal order?","I would ask for clarification: 'I want to make sure I understand correctly. Can you repeat the medication name and dose? I want to verify the spelling.' I would read the order back for confirmation. I would never implement an order I do not understand—patient safety depends on clear communication.","Read-back verification for unclear orders.","beginner"),
      q("sim3-11","workplace_scenarios","prioritization","A patient's family says the patient does not look right.","How would you respond to family concern about patient appearance?","I would assess the patient immediately. Family members know their loved ones and often detect subtle changes before clinical signs become obvious. I would perform vital signs, a focused assessment, and compare to baseline. If I find changes, I would notify the provider. I would always take family observations seriously.","Family observation as clinical early warning.","beginner"),
      q("sim3-12","workplace_scenarios","patient_safety","A patient is found on the floor after a fall.","What is the immediate response to a patient fall?","I would not move the patient until I assess for injury—especially head, neck, and spine injury. I would call for help, perform a focused assessment, check vital signs, and notify the provider. I would document the fall circumstances, injuries found, and interventions. I would complete an incident report and implement a fall prevention plan update.","Post-fall assessment protocol.","beginner"),
      q("sim3-13","workplace_scenarios","delegation","Your CNA reports a patient's blood pressure is 82/50.","How would you respond to a CNA reporting low blood pressure?","I would go assess the patient immediately—a BP of 82/50 is potentially dangerous. I would assess for symptoms, recheck the blood pressure myself, check for orthostasis, review medications and recent changes, and notify the provider if confirmed. I would never dismiss a CNA's report without personal verification.","Immediate clinical response to abnormal CNA report.","beginner"),
      q("sim3-14","workplace_scenarios","handoff_communication","You are receiving report and have questions about the plan of care.","How would you clarify care plan questions during handoff?","I would ask specific questions during report rather than trying to figure things out later: 'What is the plan if the patient's pain remains above 7/10?' 'Is there a specific trigger for calling the physician?' Clarifying during handoff prevents unsafe gaps in care during the transition.","Proactive handoff questioning.","beginner"),
      q("sim3-15","workplace_scenarios","medication_error","A patient tells you they are allergic to a medication you are about to give.","What do you do when a patient reports an allergy at the point of care?","I would stop immediately and not administer the medication. I would verify the allergy details, check the chart for documentation, update the allergy list if not already documented, and contact the prescriber for an alternative medication. I would also check all current orders for cross-reactive medications.","Patient-reported allergy verification and response.","beginner"),
      q("sim3-16","workplace_scenarios","difficult_coworkers","A colleague makes a mistake and asks you not to report it.","How would you handle a colleague asking you to conceal an error?","I would explain that reporting errors is a professional obligation and a safety requirement: 'I understand your concern, but reporting helps us improve systems and prevents future errors. I encourage you to self-report, which shows professionalism. If you do not report it, I have an obligation to report what I observed for patient safety.'","Professional obligation to report errors.","intermediate"),
      q("sim3-17","workplace_scenarios","patient_safety","A patient on telemetry monitoring develops a new arrhythmia.","How would you respond to a new arrhythmia on telemetry?","I would go to the patient's bedside immediately to assess their hemodynamic status. I would check pulse, blood pressure, and level of consciousness. I would obtain a rhythm strip for documentation. For unstable arrhythmias, I would call a code. For stable new arrhythmias, I would notify the provider with the rhythm strip and my assessment findings.","New arrhythmia assessment protocol.","intermediate"),
      q("sim3-18","workplace_scenarios","interdisciplinary_communication","You need to call a physician with a patient concern at 2 AM.","How would you prepare for a nighttime physician call?","I would have all information ready before calling: patient name, room number, diagnosis, current vital signs, relevant labs, my specific concern, and my assessment. I would use SBAR format. I would have the chart open in case they ask questions. Being organized and concise for nighttime calls is essential—physicians appreciate prepared, focused communication.","Prepared nighttime physician communication.","beginner"),
      q("sim3-19","workplace_scenarios","delegation","A patient needs a 1:1 sitter but none is available.","How would you manage a sitter-required patient without a sitter?","I would communicate the safety need to the charge nurse immediately, implement interim safety measures (bed alarm, frequent rounds, room near the nurses' station), explore alternatives (family member at bedside, video monitoring), and document the safety concern. I would not leave a high-risk patient without safety measures while advocating for appropriate staffing.","Resource-limited safety management.","intermediate"),
      q("sim3-20","workplace_scenarios","prioritization","Three patients need to go to radiology at the same time.","How would you coordinate multiple patient transports?","I would prioritize by clinical urgency: stat diagnostic tests first, then scheduled tests. I would coordinate with transport services for timing, ensure patients are prepared (consent, IV access, NPO status), communicate with radiology about the sequence, and ensure coverage for my remaining patients during transports.","Transport coordination with clinical prioritization.","beginner"),
    ]
  },
  {
    id: "sim-clinical-transition",
    title: "New Nurse Clinical Transition",
    description: "Navigate common challenges faced during the transition from nursing student to professional nurse. Practice managing anxiety, time management, and clinical confidence.",
    category: "clinical_transition",
    difficulty: "beginner",
    estimatedMinutes: 35,
    questions: [
      q("sim4-1","clinical_transition","first_shift","You arrive for your first shift as a licensed nurse.","What would you do to prepare for your first shift?","I would arrive early to review the unit layout and emergency equipment locations. I would introduce myself to the charge nurse and my preceptor. I would review my patient assignments and their charts before starting care. I would set realistic expectations—I will not be perfect on day one, and that is acceptable.","First shift preparation and expectations.","beginner"),
      q("sim4-2","clinical_transition","new_nurse_anxiety","You feel overwhelmed by the responsibility of being a licensed nurse.","How would you manage the weight of professional responsibility?","I would remind myself that I completed a rigorous education program and passed the NCLEX—I am prepared for this role. I would lean on my preceptor and support system. I would focus on one patient at a time rather than the entire workload. I would recognize that competence develops through experience and that asking for help is a sign of professionalism.","Competence confidence with support utilization.","beginner"),
      q("sim4-3","clinical_transition","time_management","You are behind schedule on your first day.","How would you catch up when falling behind?","I would reassess my priorities: what must be done now for patient safety versus what can be safely deferred. I would communicate with my preceptor about my timeline. I would delegate appropriate tasks. I would not rush through critical tasks like medication administration just to catch up—safety always takes priority over schedule.","Safety-first catch-up strategies.","beginner"),
      q("sim4-4","clinical_transition","documentation_challenges","You are unsure how to document a complex situation.","How would you approach unfamiliar documentation?","I would ask my preceptor for guidance, review similar documented cases in the chart, use the documentation system's templates and help features, and focus on objective, factual information. When in doubt, I would document more rather than less—thorough documentation protects the patient and the nurse.","Documentation guidance-seeking.","beginner"),
      q("sim4-5","clinical_transition","critical_thinking_drills","A patient's vital signs are different from the previous shift.","How would you evaluate vital sign changes?","I would compare current values to the patient's baseline (not just textbook normals), assess the trend direction and rate of change, correlate with the patient's clinical condition and treatments, and determine if the change is expected or concerning. I would notify the provider if changes represent a clinically significant deviation from the patient's normal.","Individualized vital sign interpretation.","beginner"),
      q("sim4-6","clinical_transition","first_shift","Your preceptor asks you to perform a skill you have only practiced in simulation.","How would you handle performing a skill for the first time on a real patient?","I would be honest: 'I have practiced this in simulation but have not performed it on a patient yet. Can you walk me through it and be present for my first attempt?' I would review the procedure steps, gather supplies, and proceed with confidence knowing my preceptor is there for guidance. First-time clinical skills require supervised practice.","Honest skill readiness with preceptor support.","beginner"),
      q("sim4-7","clinical_transition","new_nurse_anxiety","You make a minor mistake during your first week.","How would you process your first clinical mistake?","I would report it immediately, assess patient impact, and follow the incident reporting process. I would not spiral into self-blame—I would analyze what happened objectively, identify contributing factors, and develop prevention strategies. I would talk to my preceptor about it. Every nurse makes mistakes; what matters is how we respond and learn.","Healthy mistake processing.","beginner"),
      q("sim4-8","clinical_transition","time_management","You cannot get your morning assessments done before medication pass.","How would you restructure your morning workflow?","I would combine initial assessments with medication passes when possible—checking vital signs, lung sounds, and IV sites while administering morning medications. I would start with my highest-acuity patients, use brief focused assessments initially, and complete comprehensive assessments when time allows. Workflow efficiency comes with practice and unit familiarity.","Workflow restructuring through care clustering.","beginner"),
      q("sim4-9","clinical_transition","documentation_challenges","Your documentation from the shift is incomplete at handoff time.","How would you handle incomplete documentation at end of shift?","I would prioritize completing documentation for clinical events, medication administration, and any changes in patient condition. I would note in my handoff what documentation is pending. I would stay to complete essential documentation rather than leaving gaps. Going forward, I would implement point-of-care charting to prevent end-of-shift backlogs.","Documentation prioritization with prevention strategy.","beginner"),
      q("sim4-10","clinical_transition","critical_thinking_drills","A patient's lab result is flagged as critical but they look fine.","How would you reconcile a critical lab with a stable patient?","I would verify the lab result—could it be a mislabeled specimen or a lab error? I would reassess the patient for subtle signs related to the abnormality. I would notify the provider regardless of the patient's appearance, because clinical deterioration may not be immediately visible. Critical values always require provider notification and possible intervention.","Critical value management despite stable appearance.","beginner"),
      q("sim4-11","clinical_transition","first_shift","You need to give a medication through a route you are not confident with.","How would you build confidence in unfamiliar administration routes?","I would review the technique in a reference guide, ask my preceptor for demonstration and supervision, ensure I understand the anatomy and landmarks, gather all necessary supplies, and proceed methodically. I would not rush. I would reflect afterward on what went well and what I would improve next time.","Supervised skill building with reflection.","beginner"),
      q("sim4-12","clinical_transition","new_nurse_anxiety","A patient asks if you are a new nurse.","How would you respond to questions about your experience level?","I would be honest without undermining confidence: 'I am a new graduate nurse, and I bring strong training and dedication to your care. I also have an experienced team supporting me. My priority is your safety and comfort. Please do not hesitate to ask questions or raise concerns at any time.' Honesty builds trust more than pretending.","Honest experience disclosure with confidence.","beginner"),
      q("sim4-13","clinical_transition","time_management","You are struggling to complete all tasks within your shift.","When should you ask for help with workload?","I should ask for help before patient safety is compromised—not after. If I recognize that I cannot complete time-sensitive tasks safely, I would inform the charge nurse immediately: 'I have three time-sensitive tasks that overlap. Can someone help with [specific task] while I handle [priority task]?' Asking for help early prevents crises.","Proactive help-seeking before safety compromise.","beginner"),
      q("sim4-14","clinical_transition","documentation_challenges","You need to document a patient's refusal of a treatment.","What are the essential elements of refusal documentation?","I would document: the specific treatment refused, my education about risks and consequences of refusal, the patient's stated reason, their competence to refuse, alternative treatments offered, provider notification, and the patient's continued refusal after education. I would have the patient sign a refusal form. This protects both the patient and the nurse legally.","Complete refusal documentation elements.","beginner"),
      q("sim4-15","clinical_transition","critical_thinking_drills","A patient's oxygen saturation reads 75% but they are talking and appear comfortable.","How would you troubleshoot a low pulse ox reading?","I would not panic but assess the reading's reliability: check probe placement, patient's nail polish or acrylic nails, circulation to the extremity, and try a different finger or use an ear probe. I would assess the patient clinically—are they dyspneic, cyanotic, tachycardic? A 75% reading with a comfortable, talking patient likely reflects a technical issue rather than true desaturation.","Pulse oximetry troubleshooting with clinical correlation.","beginner"),
      q("sim4-16","clinical_transition","first_shift","You witness an experienced nurse using a shortcut you were taught not to use.","How would you handle observing shortcuts from experienced staff?","I would follow the proper procedure as I was taught. I would not confront the experienced nurse publicly but might ask my preceptor privately: 'I noticed something done differently from how I learned. Can you help me understand the correct approach?' I would prioritize evidence-based practice over convenience and consult facility policy.","Standards-based practice despite observed shortcuts.","beginner"),
      q("sim4-17","clinical_transition","new_nurse_anxiety","You cannot sleep before your shifts because of anxiety.","How would you manage pre-shift insomnia from anxiety?","I would develop a pre-shift routine: organize my supplies and uniform the night before, practice progressive muscle relaxation or meditation, avoid screens before bed, limit caffeine, and engage in light exercise. If anxiety is severely affecting my sleep and functioning, I would seek professional support. Adequate rest is essential for safe patient care.","Sleep hygiene and anxiety management for new nurses.","beginner"),
      q("sim4-18","clinical_transition","time_management","You spend too much time looking things up during your shift.","How would you reduce time spent on reference lookups?","I would study one clinical topic related to my patients each day before my shift. I would create pocket reference cards for common medications, lab values, and protocols. I would use smartphone apps for quick drug references. Over time, frequently needed information becomes second nature. The goal is not to memorize everything but to minimize lookup time.","Progressive knowledge building for efficiency.","beginner"),
      q("sim4-19","clinical_transition","documentation_challenges","You need to chart while simultaneously monitoring a patient.","How would you balance documentation with patient monitoring?","I would use a mobile workstation or laptop at the bedside so I can document while observing the patient. I would chart in real-time during assessments rather than trying to recall details later. For critically ill patients, I would prioritize monitoring and chart immediately after stabilization. Point-of-care documentation improves both accuracy and efficiency.","Bedside documentation for simultaneous charting and monitoring.","beginner"),
      q("sim4-20","clinical_transition","critical_thinking_drills","A patient's morning labs show several abnormal values.","How would you prioritize multiple abnormal lab values?","I would identify which abnormalities are most clinically significant based on the patient's condition: life-threatening values first (critical potassium, glucose), then values that affect current treatment (INR for anticoagulation), then trending abnormalities. I would notify the provider about all abnormalities but prioritize the most dangerous ones first using SBAR communication.","Lab result prioritization by clinical significance.","beginner"),
    ]
  },
  {
    id: "sim-professional-development",
    title: "Professional Development & Ethics",
    description: "Navigate ethical dilemmas, boundary management, and professional growth challenges commonly faced by new graduate nurses.",
    category: "professional_development",
    difficulty: "intermediate",
    estimatedMinutes: 40,
    questions: [
      q("sim5-1","professional_development","ethical_dilemmas","A patient refuses a life-saving treatment.","How do you handle refusal of life-saving treatment?","I would ensure the patient has decision-making capacity, provide thorough education about risks and consequences, explore their reasons for refusal, offer alternatives, involve the ethics committee if appropriate, and ultimately respect their autonomous decision while documenting everything thoroughly. Patient autonomy is a fundamental ethical principle.","Informed refusal with thorough documentation.","intermediate"),
      q("sim5-2","professional_development","professional_boundaries","A patient offers you a monetary gift for excellent care.","How do you handle monetary gifts from patients?","I would decline politely: 'Your kind words are the best reward I could receive. I cannot accept monetary gifts, but if you would like to recognize the team, you can contact our patient experience department.' I would follow facility policy, which typically prohibits individual monetary gifts.","Policy-compliant gift declination.","beginner"),
      q("sim5-3","professional_development","workplace_bullying","A senior nurse is consistently condescending toward you.","How would you address condescending behavior?","I would address it directly and privately: 'I respect your experience and value your guidance. However, when feedback is delivered condescendingly, it makes it harder for me to learn. I would appreciate direct, constructive feedback that helps me grow.' If behavior continued, I would document and escalate.","Assertive feedback about communication style.","intermediate"),
      q("sim5-4","professional_development","advocacy","A patient does not understand their treatment options.","How do you ensure informed decision-making?","I would assess the patient's understanding, provide education using plain language, use teach-back to verify comprehension, offer written materials, arrange for interpreter services if needed, and ensure the physician has explained all options including risks, benefits, and alternatives. Informed decision-making requires more than a signed consent form.","Comprehensive informed consent advocacy.","beginner"),
      q("sim5-5","professional_development","patient_communication","A family member is angry about their loved one's care.","How do you de-escalate an angry family member?","I would listen actively without interrupting, validate their concerns, avoid defensive responses, apologize for their negative experience, provide factual information, offer solutions when possible, and involve the charge nurse or patient advocate if needed. Most anger stems from fear, frustration, or feeling unheard.","De-escalation through active listening and validation.","beginner"),
      q("sim5-6","professional_development","ethical_dilemmas","You are asked to participate in a procedure that conflicts with your values.","How do you handle moral distress in nursing?","I would request reassignment to another patient without judgment or delay. I would not compromise patient care while seeking the reassignment. I would discuss my concerns with the charge nurse and ethics committee if needed. Nurses have the right to conscientious objection as long as patient care is not compromised.","Conscientious objection with care continuity.","intermediate"),
      q("sim5-7","professional_development","professional_boundaries","You find yourself sharing personal problems with a patient.","How do you recognize and correct boundary drift?","I would recognize the boundary crossing, redirect the conversation back to the patient: 'I appreciate you listening, but let me refocus on your care.' I would reflect on what prompted the sharing and seek support from appropriate sources (colleagues, EAP). I would be mindful of boundary drift in future interactions.","Self-awareness and boundary correction.","beginner"),
      q("sim5-8","professional_development","advocacy","A patient needs a medical accommodation that the facility does not routinely provide.","How do you advocate for non-standard accommodations?","I would research the patient's rights, present the clinical rationale to administration, involve the patient advocate, explore creative solutions, and escalate through proper channels. I would document the need and my advocacy efforts. Patients have the right to reasonable accommodations, and nursing advocacy can make them happen.","Systematic accommodation advocacy.","intermediate"),
      q("sim5-9","professional_development","patient_communication","A patient is being discharged but you are concerned about their home safety.","How do you address discharge safety concerns?","I would assess the specific safety concerns, involve social work and case management, conduct a medication teach-back, arrange home health services if needed, provide emergency contact numbers, ensure follow-up appointments are scheduled, and communicate my concerns to the medical team. Discharge planning is a critical nursing function.","Comprehensive discharge safety assessment.","beginner"),
      q("sim5-10","professional_development","ethical_dilemmas","A colleague asks you to falsify a medication time on the MAR.","How do you handle a request to falsify documentation?","I would decline clearly: 'I cannot document a false medication time. This is falsification of the medical record, which is illegal and puts the patient at risk. I encourage you to document the actual time and file an incident report if there is a concern about timeliness.' I would report the request if it represents a pattern.","Zero-tolerance for documentation falsification.","intermediate"),
      q("sim5-11","professional_development","workplace_bullying","You are excluded from unit social activities.","How do you handle social exclusion at work?","I would focus on building professional relationships through competence, reliability, and positive attitude. I would not compromise my values to fit in. I would seek connection with supportive colleagues across the organization. If exclusion extends to professional opportunities, I would address it with management. Professional respect matters more than social popularity.","Professional focus over social acceptance.","beginner"),
      q("sim5-12","professional_development","advocacy","A patient's medication is causing side effects that affect quality of life.","How do you advocate for medication modification?","I would document the side effects thoroughly, discuss them with the patient, and communicate to the provider: 'The patient reports [specific side effects] that are significantly affecting their quality of life. Are there alternative medications or dosing strategies we could consider?' I would present objective data about the side effects' impact on function and compliance.","Side effect advocacy with alternative exploration.","beginner"),
      q("sim5-13","professional_development","patient_communication","A patient asks questions you cannot answer.","How do you handle clinical questions beyond your scope?","I would be honest: 'That is an excellent question. I do not want to give you inaccurate information, so let me make sure your physician addresses this during their visit today. I will note your question so it is not forgotten.' I would document the question and follow up to ensure it is answered.","Honest knowledge limitation acknowledgment.","beginner"),
      q("sim5-14","professional_development","professional_boundaries","A patient's family invites you to their home for dinner.","How do you decline personal invitations from patients' families?","I would decline warmly: 'I am touched by your kindness. While I need to maintain my professional boundaries, please know that caring for your family member has been meaningful. I wish your family all the best.' Professional boundaries protect both the nurse and the patient relationship.","Warm boundary maintenance with families.","beginner"),
      q("sim5-15","professional_development","ethical_dilemmas","You witness a medication error by another nurse that was not reported.","How do you handle witnessing an unreported error?","I would first verify what I observed and encourage the nurse to self-report: 'I noticed the medication timing issue. I think it should be reported so we can ensure the patient is not affected.' If they refuse, I have a professional and ethical obligation to report it through proper channels for patient safety.","Encouraging self-reporting with escalation willingness.","intermediate"),
      q("sim5-16","professional_development","advocacy","A patient is in pain but the ordered analgesic is not providing adequate relief.","How do you advocate for better pain management?","I would document pain assessments showing inadequate relief, communicate to the provider using objective data: 'The patient has been at 8/10 pain despite two doses of the current analgesic. The functional impact includes inability to participate in PT and poor sleep. Can we discuss adjusting the pain management plan?' I would suggest multimodal approaches.","Data-driven pain management advocacy.","intermediate"),
      q("sim5-17","professional_development","patient_communication","A patient is overwhelmed by too much information.","How do you manage information overload for patients?","I would break education into smaller sessions, prioritize the most critical information first (safety-related), use visual aids and written materials for reference, involve family members to reinforce learning, and schedule follow-up education sessions. I would check understanding after each key point before moving on.","Staged education delivery to prevent overload.","beginner"),
      q("sim5-18","professional_development","professional_boundaries","You develop a strong emotional attachment to a dying patient.","How do you manage grief as a nurse?","I would acknowledge my feelings as valid and normal. I would seek support through debriefing with colleagues, EAP counseling, and self-care practices. I would maintain professional boundaries while allowing myself to grieve. I would attend memorial services if appropriate per facility policy. Compassion fatigue prevention requires active emotional processing.","Professional grief management with self-care.","intermediate"),
      q("sim5-19","professional_development","advocacy","A patient needs community resources but the hospital social worker is unavailable.","How do you connect patients with resources independently?","I would maintain a personal resource guide with commonly needed services: transportation, food assistance, prescription assistance, and community health centers. I would use 2-1-1 dialing for resource referrals. I would document the need in the chart for social work follow-up. Nurses should not wait for social work availability to start resource mobilization.","Independent resource navigation.","beginner"),
      q("sim5-20","professional_development","ethical_dilemmas","A patient asks you to keep a secret about their health behavior from their physician.","How do you handle patient secrets that affect their care?","I would explain that their health behavior may directly affect their treatment plan: 'I want to respect your privacy, but this information could change how we manage your care. If your physician does not know about this, your treatment may not be as effective or safe. Would you be willing to share this information?' I would document the information as clinically relevant.","Patient confidentiality balanced with clinical safety.","intermediate"),
    ]
  },
  {
    id: "sim-career-navigation",
    title: "Career Navigation for New Graduates",
    description: "Practice navigating career decisions, job negotiations, and professional development planning as a new graduate nurse.",
    category: "career_navigation",
    difficulty: "beginner",
    estimatedMinutes: 35,
    questions: [
      q("sim6-1","career_navigation","job_offer_negotiation","You receive your first job offer.","How would you evaluate your first nursing job offer?","I would evaluate: base salary and shift differentials, benefits package, orientation length and structure, nurse-to-patient ratios, unit culture and turnover rate, growth opportunities, tuition reimbursement, and work-life balance policies. I would compare to market rates and consider both financial and professional development factors.","Comprehensive first job evaluation framework.","beginner"),
      q("sim6-2","career_navigation","probation_period","You are starting your probation period.","What are your priorities during nursing probation?","My priorities are: consistent patient safety, building clinical competence progressively, developing positive relationships with the team, demonstrating reliability, accepting and acting on feedback, asking questions without hesitation, and documenting my learning progress. The goal is to earn trust through consistent, safe practice.","Probation priority establishment.","beginner"),
      q("sim6-3","career_navigation","career_advancement","You are planning your first year of professional development.","What professional goals should a first-year nurse set?","I would focus on: achieving independent practice on my unit, obtaining specialty-relevant certifications (ACLS, PALS as applicable), joining a professional organization, participating in one unit committee, developing one area of clinical expertise, and building my professional portfolio. Each goal should have a timeline and measurable outcome.","First-year professional development planning.","beginner"),
      q("sim6-4","career_navigation","job_offer_negotiation","An interviewer asks about your salary expectations.","How would you discuss salary expectations?","I would research market rates for new graduate nurses in my area and specialty. I would state a range rather than a specific number: 'Based on my research of market rates for new graduates with BSN in this area, I am looking at the range of $X to $Y. I am also interested in the total compensation package including benefits and professional development support.'","Market-informed salary discussion.","beginner"),
      q("sim6-5","career_navigation","probation_period","Your preceptor gives you negative feedback.","How would you process negative feedback during probation?","I would listen without defensiveness, ask for specific examples, take notes, and create an action plan: 'Thank you for the feedback. Can you give me a specific example so I can understand exactly what to improve? I want to create an action plan and check back with you next week to see if I am making progress.'","Structured negative feedback processing.","beginner"),
      q("sim6-6","career_navigation","career_advancement","You want to pursue specialty certification.","How would you choose and prepare for specialty certification?","I would identify certifications relevant to my practice area, check eligibility requirements (many require 1-2 years of experience), create a study plan using practice questions and review courses, budget for exam fees, and check if my employer offers reimbursement. Specialty certification demonstrates expertise and often leads to increased compensation.","Strategic certification planning.","beginner"),
      q("sim6-7","career_navigation","job_offer_negotiation","You are considering two different job offers.","How would you systematically compare two offers?","I would create a comparison matrix covering: salary, benefits value, orientation quality, mentoring support, unit culture, growth opportunities, commute, scheduling flexibility, and long-term career alignment. I would weight factors by personal importance and calculate total value. The highest salary is not always the best offer.","Systematic offer comparison methodology.","intermediate"),
      q("sim6-8","career_navigation","probation_period","You are approaching the end of orientation.","How would you prepare for independent practice?","I would identify remaining competency gaps and create a plan to address them. I would establish a network of resource nurses for different clinical questions. I would set up a 30-day check-in schedule with my manager. I would prepare mentally for the transition from supported to independent practice while recognizing that asking for help remains appropriate and expected.","Independent practice transition preparation.","beginner"),
      q("sim6-9","career_navigation","career_advancement","You are considering graduate school.","When should a new nurse consider graduate education?","I would recommend at least 1-2 years of clinical practice before starting a graduate program. This allows me to: develop a clinical foundation that informs graduate study, identify my genuine area of interest rather than guessing, build financial stability, and bring real-world experience to academic discussions. Early planning (GRE, prerequisites) can happen during this time.","Evidence-based graduate school timing.","intermediate"),
      q("sim6-10","career_navigation","performance_evaluation","You are preparing for your first formal evaluation.","How would you prepare for your first nursing evaluation?","I would gather documentation of: competencies achieved, certifications earned, committee involvement, quality improvement contributions, continuing education completed, and specific patient care achievements. I would self-assess using the evaluation criteria beforehand. I would prepare questions about growth opportunities and set professional goals for the next evaluation period.","Comprehensive evaluation preparation.","beginner"),
      q("sim6-11","career_navigation","job_offer_negotiation","The interviewer asks why you want to work at their facility.","How would you answer 'Why this facility?'","I would reference specific aspects: 'I am drawn to your facility because of your Magnet designation, which reflects a commitment to nursing excellence. Your cardiac unit's reputation for innovative patient care aligns with my clinical interests. I also appreciate your structured new graduate orientation program, which demonstrates investment in developing new nurses.'","Specific, researched facility interest.","beginner"),
      q("sim6-12","career_navigation","probation_period","You are struggling with a specific clinical skill.","How would you address a persistent skill deficit?","I would request additional practice time in the simulation lab, ask my preceptor for focused coaching on the specific skill, watch video demonstrations, and practice with supervision until I am confident. I would not avoid the skill—avoidance only delays competency. I would track my progress and celebrate improvement.","Targeted skill deficit remediation.","beginner"),
      q("sim6-13","career_navigation","career_advancement","You are interested in a specialty that your current unit does not offer.","How would you explore a specialty interest from your current position?","I would shadow nurses in the desired specialty, attend relevant conferences and CE events, pursue related certifications, network with nurses in the specialty, and apply for internal transfer when positions open. I would also develop transferable skills that strengthen my application for the specialty area.","Strategic specialty exploration from current role.","beginner"),
      q("sim6-14","career_navigation","performance_evaluation","You want to discuss career growth during your evaluation.","How would you initiate a career growth conversation?","I would prepare specific goals: 'I would like to discuss my professional development trajectory. In the next year, I am interested in pursuing charge nurse responsibilities and beginning CCRN preparation. How can we align my development plan to support these goals within our unit's needs?' Linking personal goals to unit needs shows strategic thinking.","Goal-aligned career growth initiation.","beginner"),
      q("sim6-15","career_navigation","job_offer_negotiation","You are asked about your biggest weakness in an interview.","How would you discuss a weakness authentically?","I would choose a genuine area for growth with an active improvement strategy: 'I sometimes struggle with delegating because I want to ensure everything is done to my standard. I have been working on this by practicing clear delegation with specific parameters and trusting my team members' competence. I check outcomes rather than micromanaging the process.'","Authentic weakness with active improvement.","beginner"),
      q("sim6-16","career_navigation","probation_period","Your manager asks if you are ready for independent practice.","How would you assess your own readiness for independence?","I would evaluate honestly: Can I manage my patient assignment safely without regular preceptor guidance? Do I know when to ask for help versus when I can manage independently? Am I comfortable with the unit's most common diagnoses and procedures? Do I have a reliable resource network? If I can answer yes to these questions with confidence, I am ready—while recognizing that independence does not mean isolation.","Honest self-readiness assessment.","beginner"),
      q("sim6-17","career_navigation","career_advancement","You want to become more involved in your professional organization.","How would you increase professional organization involvement?","I would attend local chapter meetings, volunteer for committees, submit abstracts for poster presentations, mentor student nurses through the organization, and pursue leadership positions within the chapter. Professional organization involvement builds networks, leadership skills, and access to continuing education—all of which accelerate career growth.","Progressive professional organization engagement.","beginner"),
      q("sim6-18","career_navigation","performance_evaluation","You receive feedback that you need to improve your communication.","How would you develop better communication skills?","I would ask for specific examples, observe strong communicators, practice SBAR consistently, seek feedback on my physician calls and handoffs, attend communication skills workshops, and ask colleagues to evaluate my patient education effectiveness. I would set measurable communication goals and track progress over 90 days.","Targeted communication skill development.","beginner"),
      q("sim6-19","career_navigation","job_offer_negotiation","You are offered a position that requires relocation.","How would you evaluate a relocation opportunity?","I would consider: career growth potential, cost of living difference, support system proximity, facility reputation, community quality, and personal readiness for change. I would visit the area, meet the team, and assess whether the professional opportunity justifies the personal disruption. I would negotiate relocation assistance.","Holistic relocation opportunity evaluation.","intermediate"),
      q("sim6-20","career_navigation","career_advancement","You want to build your leadership skills early in your career.","How can a new nurse develop leadership skills?","I would lead by example through clinical excellence, volunteer for unit projects, participate in shared governance, mentor newer students and orientees, take charge nurse assignments when ready, and pursue leadership development courses. Leadership is not a title—it is demonstrated through influence, initiative, and commitment to team success.","Early career leadership development strategies.","beginner"),
    ]
  },
  {
    id: "sim-panel-interview",
    title: "Panel Interview Preparation",
    description: "Practice handling multi-interviewer scenarios where you need to address questions from nurse managers, educators, and HR representatives simultaneously.",
    category: "interview_preparation",
    difficulty: "intermediate",
    estimatedMinutes: 45,
    questions: [
      q("sim7-1","interview_preparation","panel_interview","You face a panel with a nurse manager, educator, and HR representative.","How would you address a panel interview?","I would make eye contact with all panel members, directing primary responses to whoever asked the question while including the others. I would balance clinical examples (for the educator), teamwork and reliability examples (for the manager), and professionalism examples (for HR). I would ask each panel member a thoughtful question at the end.","Multi-audience response tailoring.","intermediate"),
      q("sim7-2","interview_preparation","panel_interview","The nurse manager asks about your clinical skills while the educator asks about your learning style.","How would you integrate clinical and learning responses?","I would connect the two: 'My strongest clinical skills are in cardiac assessment and medication administration. My learning style is hands-on with deliberate practice—I learn best by doing, then reflecting. For example, after each new cardiac patient, I review the rhythm strips and correlate with my assessment findings to deepen my understanding.'","Integrated clinical-learning response.","intermediate"),
      q("sim7-3","interview_preparation","panel_interview","HR asks about your availability while the manager asks about commitment.","How would you address scheduling and commitment together?","I would be transparent: 'I am available for all shifts including weekends and holidays. My commitment to this unit is demonstrated by my deliberate choice to apply here based on your reputation. I am looking for a long-term professional home where I can grow and contribute. I understand that new graduates typically work evening or night shifts, and I am prepared for that.'","Combined availability and commitment response.","beginner"),
      q("sim7-4","interview_preparation","panel_interview","Multiple panel members ask rapid-fire questions.","How would you manage rapid-fire questioning?","I would take a brief pause before each answer to collect my thoughts—speed is less important than thoughtfulness. I would answer each question completely but concisely. If I needed a moment, I would say, 'That is a great question. Let me think about the best example to share.' Composure under pressure is itself an answer to their assessment.","Composure under rapid questioning.","intermediate"),
      q("sim7-5","interview_preparation","panel_interview","A panel member seems disengaged during your answers.","How would you re-engage a disinterested panel member?","I would direct a particularly relevant point toward them, use their name if known, or ask a clarifying question that involves them: 'As the clinical educator, I would especially value your perspective on how new graduates develop assessment skills on this unit.' Including them shows awareness and interpersonal intelligence.","Strategic re-engagement of disinterested panelists.","intermediate"),
      q("sim7-6","interview_preparation","panel_interview","Panel members ask conflicting questions about your priorities.","How would you navigate contradictory panel questions?","I would acknowledge both perspectives: 'Both patient safety and efficiency are essential. In practice, I prioritize safety first—I would never rush a medication check to save time. However, I also believe that developing efficient workflows allows me to maintain safety while meeting all patient needs within my shift.' Showing you can hold multiple priorities simultaneously demonstrates maturity.","Balancing seemingly contradictory priorities.","intermediate"),
      q("sim7-7","interview_preparation","panel_interview","You are asked to describe a weakness by one panelist and a strength by another.","How would you connect weakness and strength responses?","I would connect them naturally: 'My greatest strength is thoroughness in patient assessment. My weakness is that this thoroughness can sometimes slow me down. I have been working on balancing detail with efficiency by developing systematic assessment routines that are both thorough and time-efficient.'","Connecting strengths and weaknesses authentically.","intermediate"),
      q("sim7-8","interview_preparation","panel_interview","The panel asks you to ask questions at the end.","What questions should you prepare for a panel interview?","I would prepare questions for each panelist: For the manager: 'What does success look like for a new graduate on your unit at 6 months?' For the educator: 'How is the orientation structured and what support is available after orientation ends?' For HR: 'What professional development opportunities does the organization offer?' Tailored questions show genuine interest.","Role-specific panel questions.","beginner"),
    ]
  },
  {
    id: "sim-difficult-questions",
    title: "Handling Difficult Interview Questions",
    description: "Practice answering the toughest questions interviewers ask, including situational questions about failure, conflict, and ethical challenges.",
    category: "interview_preparation",
    difficulty: "intermediate",
    estimatedMinutes: 40,
    questions: [
      q("sim8-1","interview_preparation","difficult_interviewer","The interviewer asks: 'Why should we hire you over other candidates?'","How would you differentiate yourself?","I would focus on my unique combination of experiences: 'I cannot speak to other candidates, but I bring strong clinical skills from diverse rotations, proven initiative through quality improvement projects, and the resilience I built from working as a CNA while completing my BSN. Most importantly, I bring genuine passion for this specific unit and patient population.'","Specific differentiation without competitor disparagement.","intermediate"),
      q("sim8-2","interview_preparation","difficult_interviewer","The interviewer asks about a time you failed.","How do you discuss failure in an interview?","I would choose a genuine failure with meaningful learning: 'I failed my first attempt at a clinical competency check. The experience was humbling, but I used it as motivation. I analyzed my mistakes, practiced extensively, and passed on my second attempt with confidence. That failure taught me that setbacks are opportunities for focused improvement.'","Authentic failure with demonstrable growth.","intermediate"),
      q("sim8-3","interview_preparation","difficult_interviewer","The interviewer asks: 'What if nursing is not what you expected?'","How would you address expectations versus reality?","I would show self-awareness: 'I understand that real nursing differs from academic expectations. I have prepared for this reality through extensive clinical experience and CNA work. I know the challenges: physical demands, emotional toll, and complex dynamics. My commitment to nursing is based on realistic experience, not idealized expectations.'","Realistic professional commitment.","intermediate"),
      q("sim8-4","interview_preparation","difficult_interviewer","The interviewer asks an unexpected or unusual question.","How would you handle a curveball interview question?","I would pause, acknowledge the question, and think aloud if needed: 'That is an interesting question I had not considered. Let me think about this...' I would give an honest, thoughtful response even if imperfect. Interviewers who ask unusual questions are assessing thinking process, not looking for a specific answer. Composure and authenticity matter more than perfection.","Handling unexpected questions with composure.","intermediate"),
      q("sim8-5","interview_preparation","difficult_interviewer","The interviewer challenges your answer.","How would you respond when an interviewer pushes back?","I would remain calm and open: 'I appreciate that perspective. You are right that there might be another approach. Can you help me understand what you would recommend in that situation? I am always looking to learn from experienced nurses.' Showing openness to feedback and willingness to learn is more impressive than defending an imperfect answer.","Graceful response to challenge.","intermediate"),
      q("sim8-6","interview_preparation","difficult_interviewer","The interviewer asks about a gap in your resume.","How would you explain a resume gap?","I would be honest and positive: 'I took time to care for a family member who was ill. That experience actually deepened my understanding of the patient and family perspective. I used the time productively by maintaining my certifications and completing continuing education courses. I am now fully committed and ready to focus on my nursing career.'","Honest gap explanation with positive framing.","beginner"),
      q("sim8-7","interview_preparation","difficult_interviewer","The interviewer seems rushed and uninterested.","How would you perform when the interviewer seems disengaged?","I would maintain my energy and professionalism regardless of the interviewer's demeanor. I would keep answers concise and impactful. I would not take their behavior personally—they may be having a difficult day. I would continue to provide strong examples and end with a confident closing statement about my interest in the position.","Maintaining performance despite interviewer demeanor.","intermediate"),
      q("sim8-8","interview_preparation","difficult_interviewer","The interviewer asks: 'Do you have any concerns about working here?'","How would you address interview concerns honestly?","I would be diplomatically honest: 'My only concern is ensuring I receive the orientation support I need to be successful. I know the transition from student to professional is challenging, and I want to make sure the orientation program provides the structure and mentoring I need. Can you describe the typical orientation experience for new graduates?'","Honest concern expression with solution focus.","beginner"),
      q("sim8-9","interview_preparation","difficult_interviewer","You are asked to role-play a patient scenario during the interview.","How would you approach an interview role-play?","I would treat it like a real clinical scenario: assess the situation, think aloud so they can follow my reasoning, ask clarifying questions, prioritize patient safety, and demonstrate my clinical thinking process. I would not rush—taking a moment to organize my thoughts shows clinical discipline. The process matters more than the specific answer.","Clinical role-play with visible reasoning.","intermediate"),
      q("sim8-10","interview_preparation","difficult_interviewer","The interviewer asks if you have other offers.","How would you handle questions about other job opportunities?","I would be honest without using it as leverage: 'I am in discussions with a few organizations, but this position is my top choice because of your unit's reputation and the quality of your orientation program. I am making my decision based on where I can provide the best patient care and develop professionally.'","Honest multi-offer disclosure without manipulation.","beginner"),
    ]
  },
  {
    id: "sim-medication-safety",
    title: "Medication Safety Scenarios",
    description: "Practice responding to medication-related scenarios including error prevention, drug interactions, and safe administration techniques.",
    category: "workplace_scenarios",
    difficulty: "intermediate",
    estimatedMinutes: 35,
    questions: [
      q("sim9-1","workplace_scenarios","medication_error","You notice a high-alert medication order without the required double-check.","How would you handle a high-alert medication without proper verification?","I would not administer it until an independent double-check is completed by another RN. High-alert medications like insulin, heparin, and chemotherapy require dual verification because errors with these drugs are more likely to cause significant harm. I would document the verification and never skip this safety step.","High-alert medication dual verification requirement.","intermediate"),
      q("sim9-2","workplace_scenarios","medication_error","A patient receives a medication through a nasogastric tube that should not be crushed.","What medications cannot be given through an NG tube?","Extended-release, enteric-coated, and sublingual medications should not be crushed for NG administration. I would contact pharmacy for an alternative formulation—liquid, immediate-release, or injectable. I would maintain a personal reference list of non-crushable medications for my unit's common drugs. Crushing certain medications can cause overdose or loss of efficacy.","Non-crushable medication awareness for tube administration.","intermediate"),
      q("sim9-3","workplace_scenarios","medication_error","You are about to give a medication but the barcode scan fails.","How would you handle a barcode scanning failure?","I would not override the scan without investigation. I would verify the five rights manually, check for the correct NDC number, ensure the medication matches the order, try rescanning, and contact pharmacy if discrepancies exist. Override should only occur with pharmacist verification when the system is genuinely malfunctioning—not as a convenience shortcut.","Barcode failure management without convenience overrides.","beginner"),
      q("sim9-4","workplace_scenarios","medication_error","A patient on multiple antibiotics develops C. difficile infection.","What nursing considerations exist for antibiotic-associated C. diff?","I would implement contact precautions with dedicated equipment, ensure hand washing with soap and water (alcohol sanitizer does not kill C. diff spores), discontinue unnecessary antibiotics per provider order, initiate appropriate C. diff treatment, monitor for dehydration, and educate about hand hygiene. Prevention of spread is critical in the hospital setting.","C. diff management and infection prevention.","intermediate"),
      q("sim9-5","workplace_scenarios","medication_error","You notice a potential drug-food interaction during meal service.","How would you manage a drug-food interaction?","I would hold the medication or adjust timing if there is a clinically significant interaction. Common examples: warfarin and vitamin K foods, MAOIs and tyramine-containing foods, levothyroxine and calcium-containing foods. I would educate the patient about food interactions and ensure dietary and pharmacy teams are aware.","Drug-food interaction management and education.","beginner"),
      q("sim9-6","workplace_scenarios","medication_error","A patient asks to self-administer their own insulin.","How would you support patient self-administration in the hospital?","I would assess the patient's ability and desire to self-administer, verify the order allows self-administration, observe their technique, ensure they can accurately measure the dose, provide the insulin at the correct time, and document their self-administration. This supports independence and discharge readiness while maintaining safety.","Supported self-administration with competency verification.","beginner"),
      q("sim9-7","workplace_scenarios","medication_error","A night shift nurse asks you to prepare a medication for a patient you are not assigned to.","How would you handle a medication preparation request for another nurse's patient?","I would decline to prepare medications for patients I am not assigned to. The nurse administering the medication should prepare it—this maintains the safety principle that the person administering verifies the five rights throughout the process. Having one nurse prepare and another administer breaks the chain of verification.","Maintaining the preparation-administration chain of verification.","intermediate"),
      q("sim9-8","workplace_scenarios","medication_error","A patient on multiple medications has a new prescription that requires renal dose adjustment.","How would you verify renal dosing?","I would check the patient's current creatinine and GFR, verify that the prescribed dose is appropriate for their renal function level, consult with the pharmacist, and communicate with the provider if adjustment is needed. Many medications require dose reduction in renal impairment—failure to adjust can cause toxicity.","Renal dose adjustment verification.","intermediate"),
      q("sim9-9","workplace_scenarios","medication_error","A patient tells you a medication makes them feel 'weird' but cannot describe specific symptoms.","How would you investigate vague medication concerns?","I would take the concern seriously. I would ask targeted questions: timing of the feeling, relationship to medication administration, what 'weird' means to them (dizziness, palpitations, nausea?). I would check for known side effects, assess vital signs and neurological status, and document the complaint. I would report the concern to the provider for evaluation.","Investigating vague medication complaints.","beginner"),
      q("sim9-10","workplace_scenarios","medication_error","You are preparing to give a medication that requires dilution.","How would you ensure safe medication dilution?","I would verify the correct diluent type (NS, D5W, sterile water), correct volume, concentration, and compatibility. I would use a syringe for accurate measurement. I would label the prepared medication immediately with drug name, concentration, date, time, and my initials. I would refer to drug references for dilution requirements rather than relying on memory.","Safe dilution practice with immediate labeling.","beginner"),
    ]
  },
  {
    id: "sim-patient-communication",
    title: "Patient Communication Mastery",
    description: "Practice therapeutic communication techniques for challenging patient interactions including difficult conversations, education, and emotional support.",
    category: "professional_development",
    difficulty: "intermediate",
    estimatedMinutes: 40,
    questions: [
      q("sim10-1","professional_development","patient_communication","A patient is receiving bad news about test results.","How would you support a patient receiving bad news?","I would ensure the physician delivers the information with adequate time and privacy. I would remain present for emotional support. I would let the patient process before offering information. I would ask, 'What questions do you have?' rather than overwhelming them. I would provide written resources for later review and arrange follow-up support.","Bad news support with patient-paced processing.","intermediate"),
      q("sim10-2","professional_development","patient_communication","A patient does not trust healthcare providers.","How would you build trust with a distrustful patient?","I would be consistently honest, follow through on every commitment, explain everything I am doing and why, give them control where possible, and never dismiss their concerns. I would not take their distrust personally—it is often based on past experiences. Trust is built through reliable actions over time, not through words alone.","Consistency-based trust building.","intermediate"),
      q("sim10-3","professional_development","patient_communication","A patient is in denial about their chronic disease.","How would you approach a patient in denial?","I would not force acceptance. I would provide factual information without judgment, explore their understanding, acknowledge that adjustment takes time, and remain available. I would use motivational interviewing: 'On a scale of 1-10, how important is managing your diabetes? What would it take to move that number up?' Meeting patients where they are is more effective than pushing.","Motivational interviewing for denial management.","intermediate"),
      q("sim10-4","professional_development","patient_communication","A patient is experiencing anticipatory nausea before chemotherapy.","How would you manage anticipatory treatment anxiety?","I would validate their experience, provide relaxation techniques before treatment, suggest distraction methods during infusion, ensure pre-medications are administered timely, and offer a calm environment. I would also explore whether anti-anxiety medication before treatment might help. Anticipatory symptoms are real physiological responses to conditioned anxiety.","Multi-modal anticipatory symptom management.","intermediate"),
      q("sim10-5","professional_development","patient_communication","A young adult patient resists health teaching.","How would you engage a resistant young adult patient?","I would adjust my approach to their developmental stage: use technology and apps, connect health management to their goals (sports, career, relationships), involve peer support, and respect their autonomy. I would provide information in brief, relevant segments rather than lectures. I would ask what they already know and build from there.","Developmentally appropriate patient engagement.","intermediate"),
      q("sim10-6","professional_development","patient_communication","A patient is worried about burdening their family.","How would you address a patient's caregiver burden concerns?","I would validate their concern while reframing: 'It is natural to worry about your family. Many families say that helping their loved one is meaningful to them. Let me also connect you with resources that can reduce the burden: home health services, support groups, and respite care. You do not have to rely on family alone.'","Burden concern validation with resource provision.","beginner"),
      q("sim10-7","professional_development","patient_communication","A patient becomes tearful during a routine assessment.","How would you respond to unexpected patient emotion?","I would pause the assessment, offer tissues, and sit quietly: 'I can see you are having a difficult moment. Take your time—there is no rush.' I would not rush to fix or explain away their tears. I would assess for depression or grief, and document the emotional assessment. Sometimes the most therapeutic intervention is simply being present.","Presence-based emotional response.","beginner"),
      q("sim10-8","professional_development","patient_communication","A patient speaks only through their family translator.","How would you ensure accurate communication with a language barrier?","I would arrange a certified medical interpreter for all clinical conversations—family members should not serve as medical interpreters due to accuracy and privacy concerns. I would use simple language, allow adequate time, use visual aids, and verify understanding through teach-back via the interpreter. I would document the interpretation method used.","Professional interpretation standard.","beginner"),
      q("sim10-9","professional_development","patient_communication","A patient is angry about a long emergency department wait.","How would you de-escalate a patient angry about wait times?","I would acknowledge their frustration: 'I understand you have been waiting a long time, and that is frustrating. Let me explain what has been happening and what the next steps are.' I would provide specific information, offer comfort measures during the wait, and update them regularly. Transparency about wait times reduces anger more than empty apologies.","Transparency-based wait time de-escalation.","beginner"),
      q("sim10-10","professional_development","patient_communication","A patient is preparing for a difficult conversation with their family about their wishes.","How would you support a patient preparing for an advance care planning discussion?","I would help them organize their thoughts: 'What matters most to you about your care? What are you most worried about? What do you want your family to understand?' I would offer to be present during the conversation for support. I would provide advance directive resources and ensure their documented wishes are updated in the medical record.","Advance care planning conversation support.","intermediate"),
    ]
  },
];
